import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const TaskManager = () => {
  const { user } = useAuth();
  const { tasks, addTask, deleteTask, staffList, disciplineTypes } = useData();
  
  const activeDisciplines = disciplineTypes.filter(d => d.status === 'Active');
  const isScheduler = user?.role === 'scheduler';

  // --- STATE CHO SCHEDULER (LỊCH CÔNG TÁC) ---
  const [scheduleList, setScheduleList] = useState([]);
  const [scheduleForm, setScheduleForm] = useState({
      repeatWeeks: 1,
      selectedDays: [] // ['Mon', 'Tue', ...]
  });
  const [editingScheduleId, setEditingScheduleId] = useState(null);

  // Load lịch từ localStorage khi component mount (Mô phỏng đồng bộ)
  useEffect(() => {
      const savedSchedules = localStorage.getItem('app_schedules');
      if (savedSchedules) {
          setScheduleList(JSON.parse(savedSchedules));
      }
  }, []);

  // --- STATE CHO TASK MANAGER ---
  const [newTask, setNewTask] = useState({ 
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', // Time
      assignedRole: 'ST',
      paymentType: 'UBI 1', // UBI 1, UBI 2, Remuneration
      disciplineId: '' // Hình thức kỷ luật
  });

  // --- LOGIC TASK (CHUNG) ---
  const handleAdd = (e) => {
    e.preventDefault();
    if (!newTask.title || !newTask.assigneeId || !newTask.endTime) return alert("Vui lòng điền đủ thông tin!");
    
    const staff = staffList.find(s => s.id === newTask.assigneeId);
    const disc = activeDisciplines.find(d => d.id === newTask.disciplineId);

    addTask({ 
        ...newTask, 
        assigneeName: staff ? staff.name : 'Unknown',
        disciplineName: disc ? disc.name : 'Chưa quy định',
        // Nếu là Scheduler thì mặc định không có tiền và kỷ luật
        paymentType: isScheduler ? 'N/A' : newTask.paymentType,
        disciplineId: isScheduler ? null : newTask.disciplineId,
        deadline: newTask.endTime 
    });
    
    setNewTask({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', paymentType: 'UBI 1', disciplineId: '' });
    alert("Đã giao việc thành công!");
  };

  const handleDelete = (id) => {
    if (window.confirm("Xóa nhiệm vụ này?")) deleteTask(id);
  };

  // --- LOGIC SCHEDULER (LÊN LỊCH) ---
  const handleDayToggle = (day) => {
      const current = scheduleForm.selectedDays;
      if (current.includes(day)) {
          setScheduleForm({ ...scheduleForm, selectedDays: current.filter(d => d !== day) });
      } else {
          setScheduleForm({ ...scheduleForm, selectedDays: [...current, day] });
      }
  };

  const handleSaveSchedule = () => {
      if (scheduleForm.repeatWeeks < 1) return alert("Số tuần lặp lại phải lớn hơn 0");
      if (scheduleForm.selectedDays.length === 0) return alert("Vui lòng chọn ít nhất 1 ngày trong tuần");

      let updatedList;
      if (editingScheduleId) {
          // Update existing
          updatedList = scheduleList.map(s => s.id === editingScheduleId ? { ...s, ...scheduleForm } : s);
          setEditingScheduleId(null);
          alert("Đã cập nhật lịch công tác!");
      } else {
          // Add new
          const newSchedule = {
              id: Date.now(),
              createdBy: user.username,
              createdAt: new Date().toISOString(),
              ...scheduleForm
          };
          updatedList = [...scheduleList, newSchedule];
          alert("Đã lưu lịch công tác mới!");
      }

      setScheduleList(updatedList);
      localStorage.setItem('app_schedules', JSON.stringify(updatedList)); // Đồng bộ
      setScheduleForm({ repeatWeeks: 1, selectedDays: [] }); // Reset form
  };

  const handleDeleteSchedule = (id) => {
      if (window.confirm("Bạn có chắc muốn xóa lịch trình này?")) {
          const updatedList = scheduleList.filter(s => s.id !== id);
          setScheduleList(updatedList);
          localStorage.setItem('app_schedules', JSON.stringify(updatedList));
      }
  };

  const handleEditSchedule = (s) => {
      setEditingScheduleId(s.id);
      setScheduleForm({ repeatWeeks: s.repeatWeeks, selectedDays: s.selectedDays });
  };

  return (
    <div style={{ paddingBottom: '20px' }}>
      <h2 style={{ color: '#003366' }}>
          {isScheduler ? 'Lên lịch & Phân công (Scheduler)' : 'Quản lý Nhiệm vụ (Op Admin)'}
      </h2>

      {/* --- PHẦN 1: LÊN LỊCH CÔNG TÁC (CHỈ HIỆN CHO SCHEDULER) --- */}
      {isScheduler && (
        <div style={{ background: '#fff', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', marginBottom: '24px', border: '1px solid #e0e7ff' }}>
            <h4 style={{ margin: '0 0 15px 0', color: '#003366', borderBottom: '1px solid #eee', paddingBottom: '10px' }}>
                {editingScheduleId ? '✏️ Điều chỉnh lịch công tác' : '📅 Lên lịch công tác'}
            </h4>
            
            <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap', alignItems: 'flex-start' }}>
                {/* Input số tuần */}
                <div style={{flex: '0 0 150px'}}>
                    <label style={styles.label}>Số tuần lặp lại</label>
                    <input 
                        type="number" min="1"
                        value={scheduleForm.repeatWeeks} 
                        onChange={e => setScheduleForm({...scheduleForm, repeatWeeks: Number(e.target.value)})} 
                        style={styles.input} 
                    />
                </div>

                {/* Checkbox Days */}
                <div style={{flex: 1}}>
                    <label style={styles.label}>Chọn ngày trong tuần</label>
                    <div style={{display:'flex', gap:'10px', marginTop:'8px', flexWrap:'wrap'}}>
                        {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map(day => (
                            <div key={day} 
                                onClick={() => handleDayToggle(day)}
                                style={{
                                    padding: '8px 12px', borderRadius: '6px', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 'bold',
                                    border: scheduleForm.selectedDays.includes(day) ? '1px solid #003366' : '1px solid #ccc',
                                    background: scheduleForm.selectedDays.includes(day) ? '#003366' : 'white',
                                    color: scheduleForm.selectedDays.includes(day) ? 'white' : '#555'
                                }}
                            >
                                {day}
                            </div>
                        ))}
                    </div>
                </div>

                <button onClick={handleSaveSchedule} style={{...styles.btnSubmit, width: 'auto', alignSelf: 'center', marginTop: '10px', background: editingScheduleId ? '#f59e0b' : '#003366'}}>
                    {editingScheduleId ? 'Lưu thay đổi' : 'Lưu lịch'}
                </button>
                {editingScheduleId && (
                    <button onClick={() => { setEditingScheduleId(null); setScheduleForm({repeatWeeks:1, selectedDays:[]}) }} style={{...styles.btnSubmit, width: 'auto', alignSelf: 'center', marginTop: '10px', background: '#9ca3af'}}>
                        Hủy
                    </button>
                )}
            </div>
        </div>
      )}

      {/* --- PHẦN 2: DANH SÁCH LỊCH ĐÃ THIẾT LẬP (CHỈ HIỆN CHO SCHEDULER) --- */}
      {isScheduler && scheduleList.length > 0 && (
          <div style={{ background: 'white', padding: '20px', borderRadius: '16px', marginBottom: '24px', border: '1px solid #eee' }}>
             <h4 style={{margin: '0 0 15px 0', color: '#003366'}}>Danh sách lịch đã thiết lập</h4>
             <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '15px'}}>
                 {scheduleList.map(s => (
                     <div key={s.id} style={{background: '#f9fafb', padding: '15px', borderRadius: '8px', border: '1px solid #e5e7eb', position: 'relative'}}>
                         <div style={{fontWeight: 'bold', color: '#374151'}}>Lặp lại: {s.repeatWeeks} tuần</div>
                         <div style={{marginTop: '8px', display: 'flex', gap: '5px', flexWrap: 'wrap'}}>
                             {s.selectedDays.map(d => (
                                 <span key={d} style={{fontSize: '0.75rem', background: '#dbeafe', color: '#1e40af', padding: '2px 6px', borderRadius: '4px'}}>{d}</span>
                             ))}
                         </div>
                         <div style={{marginTop: '15px', display: 'flex', gap: '10px', fontSize: '0.85rem'}}>
                             <button onClick={() => handleEditSchedule(s)} style={{color: '#003366', background: 'none', border: 'none', cursor: 'pointer', fontWeight: '600'}}>Điều chỉnh</button>
                             <button onClick={() => handleDeleteSchedule(s.id)} style={{color: '#ef4444', background: 'none', border: 'none', cursor: 'pointer'}}>Xóa</button>
                         </div>
                     </div>
                 ))}
             </div>
          </div>
      )}

      {/* --- PHẦN 3: FORM GIAO VIỆC (TASK MỚI) --- */}
      <div style={{ background: 'white', padding: '24px', borderRadius: '16px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', marginBottom: '24px' }}>
        <h4 style={{ margin: '0 0 20px 0' }}>Giao nhiệm vụ cụ thể</h4>
        <form onSubmit={handleAdd} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
          
          <div style={{ gridColumn: '1 / -1' }}>
             <label style={styles.label}>Tiêu đề công việc</label>
             <input value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} style={styles.input} required />
          </div>

          <div>
             <label style={styles.label}>Người thực hiện</label>
             <select value={newTask.assigneeId} onChange={e => setNewTask({...newTask, assigneeId: e.target.value})} style={styles.select} required>
                <option value="">-- Chọn nhân sự --</option>
                {staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}
             </select>
          </div>

          <div>
             <label style={styles.label}>Vai trò thực hiện</label>
             <select value={newTask.assignedRole} onChange={e => setNewTask({...newTask, assignedRole: e.target.value})} style={styles.select}>
                {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}
             </select>
          </div>

          <div>
             <label style={styles.label}>Bắt đầu (Check-in)</label>
             <input type="datetime-local" value={newTask.startTime} onChange={e => setNewTask({...newTask, startTime: e.target.value})} style={styles.input} required />
          </div>

          <div>
             <label style={styles.label}>Kết thúc (Check-out)</label>
             <input type="datetime-local" value={newTask.endTime} onChange={e => setNewTask({...newTask, endTime: e.target.value})} style={styles.input} required />
          </div>

          {/* CHỈ HIỆN PAYMENT VÀ DISCIPLINE NẾU KHÔNG PHẢI LÀ SCHEDULER */}
          {!isScheduler && (
            <>
              <div>
                 <label style={styles.label}>Loại chi trả</label>
                 <select value={newTask.paymentType} onChange={e => setNewTask({...newTask, paymentType: e.target.value})} style={styles.select}>
                    <option value="UBI 1">UBI 1</option>
                    <option value="UBI 2">UBI 2</option>
                    <option value="Remuneration">Remuneration</option>
                 </select>
              </div>

              <div>
                 <label style={styles.label}>Kỷ luật (nếu trễ)</label>
                 <select value={newTask.disciplineId} onChange={e => setNewTask({...newTask, disciplineId: e.target.value})} style={{...styles.select, borderColor: 'red', color: '#b91c1c'}}>
                    <option value="">-- Chọn hình thức (Đã duyệt) --</option>
                    {activeDisciplines.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                 </select>
              </div>
            </>
          )}

          <div style={{ gridColumn: '1 / -1' }}>
             <label style={styles.label}>Mô tả chi tiết</label>
             <textarea value={newTask.description} onChange={e => setNewTask({...newTask, description: e.target.value})} style={{...styles.input, height: '80px'}} />
          </div>

          <button type="submit" style={styles.btnSubmit}>Giao việc</button>
        </form>
      </div>

      {/* --- PHẦN 4: DANH SÁCH NHIỆM VỤ --- */}
      <div style={{ background: 'white', padding: '20px', borderRadius: '16px' }}>
         <h4>Danh sách đang thực hiện</h4>
         <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
            <thead>
               <tr style={{textAlign:'left', borderBottom: '1px solid #eee'}}>
                 <th style={{padding:'10px'}}>Nhiệm vụ</th>
                 <th>Người làm</th>
                 <th>Vai trò</th>
                 <th>Hạn chót</th>
                 {/* Scheduler không cần xem cột tiến độ chi tiết liên quan tài chính, nhưng cứ hiển thị cơ bản */}
                 <th>Tiến độ</th>
                 <th>Xóa</th>
               </tr>
            </thead>
            <tbody>
               {tasks.map(t => (
                 <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                    <td style={{padding:'10px'}}>
                        <strong>{t.title}</strong><br/>
                        <span style={{fontSize:'0.75rem', color:'#666'}}>{t.paymentType}</span>
                    </td>
                    <td>{t.assigneeName}</td>
                    <td>{t.assignedRole}</td>
                    <td>{new Date(t.endTime).toLocaleString()}</td>
                    <td>{t.progress}%</td>
                    <td><button onClick={()=>handleDelete(t.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Xóa</button></td>
                 </tr>
               ))}
            </tbody>
         </table>
      </div>
    </div>
  );
};

const styles = {
    input: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', boxSizing: 'border-box' },
    select: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', background: 'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555' },
    btnSubmit: { gridColumn: '1 / -1', padding: '12px', background: '#003366', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' }
};

export default TaskManager;
